  1575→   public:
  1576→    explicit MaybeClearDestroyedFrames(DestroyedFramesT& aTarget)
  1577→        : mDestroyedFramesRef(aTarget),
  1578→          mResetOnDestruction(!aTarget)  // reset only if target starts out null
  1579→    {}
  1580→    ~MaybeClearDestroyedFrames() {
  1581→      if (mResetOnDestruction) {
  1582→        mDestroyedFramesRef.reset(nullptr);
  1583→      }
  1584→    }
  1585→  };
