2747→bool RestyleManager::ProcessPostTraversal(Element* aElement,
  2748→                                          ServoRestyleState& aRestyleState,
  2749→                                          ServoPostTraversalFlags aFlags) {
  2750→  nsIFrame* styleFrame = nsLayoutUtils::GetStyleFrame(aElement);
  2751→  nsIFrame* primaryFrame = aElement->GetPrimaryFrame();
  2752→
  2753→  MOZ_DIAGNOSTIC_ASSERT(aElement->HasServoData(),
  2754→                        "Element without Servo data on a post-traversal? How?");
  2755→
  2756→  // NOTE(emilio): This is needed because for table frames the bit is set on the
  2757→  // table wrapper (which is the primary frame), not on the table itself.
  2758→  const bool isOutOfFlow =
  2759→      primaryFrame && primaryFrame->HasAnyStateBits(NS_FRAME_OUT_OF_FLOW);
  2760→
  2761→  const bool canUseHandledHints =
  2762→      primaryFrame && CanUseHandledHintsFromAncestors(primaryFrame);
  2763→
  2764→  // Grab the change hint from Servo.
  2765→  bool wasRestyled = false;
  2766→  nsChangeHint changeHint =
  2767→      static_cast<nsChangeHint>(Servo_TakeChangeHint(aElement, &wasRestyled));
  2768→
  2769→  RefPtr<ComputedStyle> upToDateStyleIfRestyled =
  2770→      wasRestyled ? ServoStyleSet::ResolveServoStyle(*aElement) : nullptr;
  2771→
  2772→  // We should really fix the weird primary frame mapping for image maps
  2773→  // (bug 135040)...
  2774→  if (styleFrame && styleFrame->GetContent() != aElement) {
  2775→    MOZ_ASSERT(styleFrame->IsImageFrameOrSubclass());
  2776→    styleFrame = nullptr;
  2777→  }
  2778→
  2779→  // Handle lazy frame construction by posting a reconstruct for any lazily-
  2780→  // constructed roots.
  2781→  if (aElement->HasFlag(NODE_NEEDS_FRAME)) {
  2782→    changeHint |= nsChangeHint_ReconstructFrame;
  2783→    MOZ_ASSERT(!styleFrame);
  2784→  }
  2785→
  2786→  if (styleFrame) {
  2787→    MOZ_ASSERT(primaryFrame);
  2788→
  2789→    nsIFrame* maybeAnonBoxChild;
  2790→    if (isOutOfFlow) {
  2791→      maybeAnonBoxChild = primaryFrame->GetPlaceholderFrame();
  2792→    } else {
  2793→      maybeAnonBoxChild = primaryFrame;
  2794→    }
  2795→
  2796→    // Do not subsume change hints for the column-spanner.
  2797→    if (canUseHandledHints) {
  2798→      changeHint = NS_RemoveSubsumedHints(
  2799→          changeHint, aRestyleState.ChangesHandledFor(styleFrame));
  2800→    }
  2801→
  2802→    // If the parent wasn't restyled, the styles of our anon box parents won't
  2803→    // change either.
  2804→    if ((aFlags & ServoPostTraversalFlags::ParentWasRestyled) &&
  2805→        maybeAnonBoxChild->ParentIsWrapperAnonBox()) {
  2806→      aRestyleState.AddPendingWrapperRestyle(
  2807→          ServoRestyleState::TableAwareParentFor(maybeAnonBoxChild));
  2808→    }
  2809→
  2810→    // If we don't have a ::marker or ::backdrop pseudo-element, but need it,
  2811→    // then reconstruct the frame.  (The opposite situation implies 'display'
  2812→    // changes so doesn't need to be handled explicitly here.)
  2813→    if (wasRestyled && !(changeHint & nsChangeHint_ReconstructFrame) &&
  2814→        NeedsToReframeForConditionallyCreatedPseudoElement(
  2815→            aElement, upToDateStyleIfRestyled, styleFrame, aRestyleState)) {
  2816→      changeHint |= nsChangeHint_ReconstructFrame;
  2817→    }
  2818→  }
  2819→
  2820→  // Although we shouldn't generate non-ReconstructFrame hints for elements with
  2821→  // no frames, we can still get them here if they were explicitly posted by
  2822→  // PostRestyleEvent, such as a RepaintFrame hint when a :link changes to be
  2823→  // :visited.  Skip processing these hints if there is no frame.
  2824→  if ((styleFrame || (changeHint & nsChangeHint_ReconstructFrame)) &&
  2825→      changeHint) {
  2826→    aRestyleState.ChangeList().AppendChange(styleFrame, aElement, changeHint);
  2827→  }
  2828→
  2829→  // If our change hint is reconstruct, we delegate to the frame constructor,
  2830→  // which consumes the new style and expects the old style to be on the frame.
  2831→  //
  2832→  // XXXbholley: We should teach the frame constructor how to clear the dirty
  2833→  // descendants bit to avoid the traversal here.
  2834→  if (changeHint & nsChangeHint_ReconstructFrame) {
  2835→    if (wasRestyled &&
  2836→        StaticPrefs::layout_css_scroll_anchoring_suppressions_enabled()) {
  2837→      const bool wasAbsPos =
  2838→          styleFrame &&
  2839→          styleFrame->StyleDisplay()->IsAbsolutelyPositionedStyle();
  2840→      auto* newDisp = upToDateStyleIfRestyled->StyleDisplay();
  2841→      // https://drafts.csswg.org/css-scroll-anchoring/#suppression-triggers
  2842→      //
  2843→      // We need to do the position check here rather than in
  2844→      // DidSetComputedStyle because changing position reframes.
  2845→      //
  2846→      // We suppress adjustments whenever we change from being display: none to
  2847→      // be an abspos.
  2848→      //
  2849→      // Similarly, for other changes from abspos to non-abspos styles.
  2850→      //
  2851→      // TODO(emilio): I _think_ chrome won't suppress adjustments whenever
  2852→      // `display` changes. But that causes some infinite loops in cases like
  2853→      // bug 1568778.
  2854→      if (wasAbsPos != newDisp->IsAbsolutelyPositionedStyle()) {
  2855→        aRestyleState.AddPendingScrollAnchorSuppression(aElement);
  2856→      }
  2857→    }
  2858→    ClearRestyleStateFromSubtree(aElement);
  2859→    return true;
  2860→  }
